oxy_webhelp_navlinks = {"tocId-d27248e18877":{"topics":[{"title":"Azure SQL workloads protection overview","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides policy-driven, immutable Rubrik backups for Azure         SQL Database and Azure SQL Managed Instance that supplement or replace Azure native         backups with configurable retention, on-demand snapshots, and cross-subscription         recovery.<\/p>","href":"saas\/azr_sql_protection_overview.html","attributes":{"data-id":"azr_sql_protection_overview"},"menu":{"hasChildren":false},"tocID":"azr_sql_protection_overview-d27248e18878","topics":[]},{"title":"Azure SQL native backup capabilities","shortdesc":"<p class=\"shortdesc\">Azure provides native backup solutions for Azure SQL workloads, including         Point-in-Time Retention and Long-Term Retention. While these offer foundational protection,         they have certain limitations.<\/p>","href":"saas\/azr_sql_native_backup_capability.html","attributes":{"data-id":"azr_sql_native_backup_capability"},"menu":{"hasChildren":false},"tocID":"azr_sql_native_backup_capability-d27248e18891","topics":[]},{"title":"Azure SQL native versus Rubrik backups","shortdesc":"<p class=\"shortdesc\">A comparative overview of the Azure SQL native backups and Rubrik         backups.<\/p>","href":"saas\/azr_sql_native_vs_rbk_backups.html","attributes":{"data-id":"azr_sql_native_vs_rbk_backups"},"menu":{"hasChildren":false},"tocID":"azr_sql_native_vs_rbk_backups-d27248e18902","topics":[]},{"title":"Supported Azure SQL backup and recovery types","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects Azure SQL Databases and Managed Instances by supporting         different types of backup and recovery options.<\/p>","href":"saas\/azr_sql_supp_backup_recv_types.html","attributes":{"data-id":"azr_sql_supp_backup_recv_types"},"menu":{"hasChildren":false},"tocID":"azr_sql_supp_backup_recv_types-d27248e18913","topics":[]}]}};